var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>방금 관측된 고에너지 반응은 뭔가! 피해상황 보고하라!</color>","JPN":"<color=#ffd34c>先ほど観測された高エネルギー反応は何だ！　被害状況を報告せよ！</color>","ENG":"<color=#ffd34c>What was that high energy signature just now?! I want a BDA! Now!</color>","TWN":"<color=#ffd34c>剛才觀測到的高能量反應是什麼？回報災情！</color>"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>화, 확인 불가! 반응과 함께 브리트라 타입의 식별신호가 일제히 소멸했습니다!</color>","JPN":"<color=#ffd34c>か、確認不可！　反応とともにブリトラタイプの識別シグナルが一斉に消滅しました！</color>","ENG":"<color=#ffd34c>B-battle damage assessment impossible! All the Britras' signatures vanished with that high energy pulse!</color>","TWN":"<color=#ffd34c>無…無法確認！反應和佈雷特類型的識別信號都一起消失不見！</color>"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아쉽군요. 사적인 용도로 사용하면 이산화탄소 배출량 감소에 일조할 수 있었을 텐데.","JPN":"残念ですね。プライベートな用途で使えば、人口減少による二酸化炭素排出量の減少の一助になったのに。","ENG":"Too bad. If I had put this ability to personal use, I would have contributed to a dramatic reduction in the global carbon emissions.","TWN":"真可惜，用在私人用途上的話，對於減少排放二氧化碳會非常有幫助。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너, 너……. 방금 그건…….","JPN":"き、貴様……もしかして今のは……","ENG":"Y-you… What was that just now…?","TWN":"你……剛才那是……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전투용 프레임으로 교전 형태를 취했을 뿐입니다.","JPN":"戦闘用フレームで交戦モードに切り替えただけです。","ENG":"I merely switched my posture to my combat frame.","TWN":"只是使用戰鬥型軀殼採取交戰型態而已。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들도 싸울 때는 자세를 잡지 않습니까. 비슷하다고 할 수 있겠군요.","JPN":"ヒューマンたちもケンカをする時は身構えるでしょう。似たようなものです。","ENG":"Humans take certain postures when they fight as well, don't they? You could say it's something like that.","TWN":"人類打架時不是會有些姿勢嗎？就類似那樣。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"기계, 기계 따위가……. 어떻게…….","JPN":"き、機械ごときが……どうやって……","ENG":"But you're just a machine… How is this possible…","TWN":"機器…不過就是個機器…怎麼會……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이면세계를 수색할 때도, 셰나에게 궁지에 몰렸을 때도. 몇 번씩 사용하고 싶었지만 참았습니다.","JPN":"裏世界を捜索する時も、シェナに窮地に追い込まれた時も。何度も使いたかったのですが我慢していました。","ENG":"When we searched the Counterside, and when Shena almost cornered me… I wanted to use it many times, but I held myself back.","TWN":"雖然在搜查異界時，以及被世娜逼到絕境時，是有想過用個幾次，但最後還是有忍住。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 기계이기 때문에 휴먼보다 충동 억제 능력이 우수한 덕이죠.","JPN":"私は機械なので、ヒューマンに比べて衝動抑制能力に優れているおかげです。","ENG":"Being a machine, I do possess more disciplined self-restraint when compared to humans.","TWN":"這都要歸功於我是機器，控制衝動的能力比人卓越。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그게 뭐야……. 대체 뭐냐고…….","JPN":"何だよそれ……いったい何なんだよ……","ENG":"But that's ridiculous… This makes no sense whatsoever…","TWN":"胡說什麼……聽不懂……"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"바, 바보 아냐……? 그런 힘을 가지고도…… 대체 왜……!","JPN":"バ、バカじゃないのか……？　そんな力を持って……いったいどうして……！","ENG":"A-are you stupid? Even with an immense power like that… Why would you…","TWN":"你…你是白癡嗎……？有這種能力……為什麼還……！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 그 꼴로 싸돌아다니면 커뮤니케이션은 고사하고 관리국에 뭇매부터 맞습니다.","JPN":"私があの格好で歩き回ると、コミュニケーションどころか管理局に袋叩きされる可能性が高いので。","ENG":"If I went around like that, I'd be welcoming a direct hit from the Administration before I could engage in any communication.","TWN":"我用那個模樣四處晃的話，別說要溝通，應該會先被管理局圍攻。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"따라서 현재의 <color=#ffd34c>비전투 형태</color>는 휴먼들과의 커뮤니케이션에서 필수적입니다. 이터니움 소모가 심각하지만요.","JPN":"したがって、現在の<color=#ffd34c>非戦闘モード</color>はヒューマンとのコミュニケーションにおいて欠かせません。エタニウムの消耗はかなり深刻ですが。","ENG":"This <color=#ffd34c>non-combat form</color> is therefore essential in enabling communication with humans. Though, granted, it does consume a considerable amount of Eternium.","TWN":"因此必須像現在這樣的<color=#ffd34c>非戰鬥型態</color>，才能和人類溝通。只是永恆之金的消耗量比較大。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"웃기지 마!!","JPN":"ふざけんなよ！！","ENG":"I refuse to believe this!","TWN":"你要笑死我！！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"너 같은 기계 따위가 4종 침식체들을 해치웠다고?!","JPN":"貴様みたいな機械ごときが第4種侵食体を倒しただと！？","ENG":"There's no way a machine like you could defeat Category 4 C.O.s!","TWN":"像你這種機器怎麼可能滅掉4類侵蝕體？！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"게다가 현실 붕괴 현상은 왜 중단된 건데! 왜 아무 일 없었다는 듯이 서 있는 거야!","JPN":"それに現実崩壊現象はなんで中断されたんだ！　どうして何事もなかったかのようにそこに立っているんだよ！","ENG":"And why did reality stop collapsing?! How come you're just standing there as if nothing happened?","TWN":"而且為什麼還中斷現世崩壞現象！為什麼一副什麼事都沒發生過的樣子站在我面前！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"농담이라고 해, 제발 농담이라고 말해!! 이건 전부 개념 없는 어떤 놈의 몰래 카메라라고 말하란 말이다!!","JPN":"冗談だよな、全部茶番だったと言え！！　これは全部悪趣味なやつのドッキリだったって言えよ！！","ENG":"Please tell me you're just pulling my leg!! Tell me this is some inane hidden camera prank!!","TWN":"拜託告訴我這都只是在開玩笑！！這只是整人節目的橋段！！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"현실입니다. 윌버.","JPN":"現実です、ウィルバー。","ENG":"It's as real as it gets, Wilbur.","TWN":"沒有在開玩笑，韋爾伯。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};